<script>
  import { getCurrentSelectedCategoryIndex, saveCurrentSelectedCategoryIndex } from "../../data/storage";
  import { userData } from "../../store";
  import PageQuickAddModal from "./PageQuickAddModal.svelte";
  import SpeedDialItems from "./SpeedDialItems.svelte";

  const storageCategoryIndex = getCurrentSelectedCategoryIndex();
  let firstRender = true;

  let pages = [];
  let categories = [];
  let tileZoom;
  let tileGrow;
  let tileSafeZone;
  let tileMinWidth;
  let tileHeight;
  let tileGap;
  let tileBorder;
  let tileBorderRadius;
  let tileBorderColor;
  let groupTileGap;
  let groupTileBorderRadius;
  let groupTileGrow;
  let navbarCompact;
  let showPageQuickAdd;
  let showElementsShadow;
  let useFrostedGlass;
  let frostedGlassStrength;
  let frostedGlassOpacity;
  let frostedGlassColor;
  let frostedGlassAccentColor;
  let openPageInNewTab;
  let categoryBarScroll;
  let categorySwipeNavigation;
  let categorySwitchButtons;
  let startingCategoryId;

  let selectedCategoryIndex = 0;
  let selectedCategoryId = undefined;
  let showCategoryNavigation = false;

  let isQuickAddOpen = false;

  let windowInnerWidth = 0;
  
  let lastCategoryNavigationTime = Date.now();
  let swipeNavigationBoxOffset = 0;
  let isSlowSwipe = false;
  let swipeNavTimer;

  userData.subscribe((data) => {
    pages = data.pages;
    categories = data.categories;
    tileZoom = data.tileZoom;
    tileGrow = data.tileGrow;
    tileSafeZone = data.tileSafeZone;
    tileMinWidth = data.tileMinWidth;
    tileHeight = data.tileHeight;
    tileGap = data.tileGap;
    tileBorder = data.tileBorder;
    tileBorderRadius = data.tileBorderRadius;
    tileBorderColor = data.tileBorderColor;
    groupTileGap = data.groupTileGap;
    groupTileBorderRadius = data.groupTileBorderRadius;
    groupTileGrow = data.groupTileGrow;
    navbarCompact = data.navbarCompact;
    showPageQuickAdd = data.showPageQuickAdd;
    showElementsShadow = data.showElementsShadow;
    useFrostedGlass = data.useFrostedGlass;
    frostedGlassStrength = data.frostedGlassStrength;
    frostedGlassOpacity = data.frostedGlassOpacity;
    frostedGlassColor = data.frostedGlassColor;
    frostedGlassAccentColor = data.frostedGlassAccentColor;
    openPageInNewTab = data.openPageInNewTab;
    categoryBarScroll = data.categoryBarScroll;
    categorySwipeNavigation = data.categorySwipeNavigation;
    categorySwitchButtons = data.categorySwitchButtons;
    startingCategoryId = data.startingCategoryId;

    if(firstRender) {
      // Set the selected category index based on local storage when the component mounts
      let isCategorySet = false;
      
      if (startingCategoryId) {
        if (startingCategoryId === "0000" && pages.filter((page) => page.categoryId === undefined && page.isActive).length > 0) {
          selectedCategoryIndex = categories.length;
          selectedCategoryId = "0000";
          isCategorySet = true;
        }
        else {
          const categoryIndex = categories.findIndex((category) => category.id === startingCategoryId);
          if (categoryIndex !== -1) {
            selectedCategoryIndex = categoryIndex;
            selectedCategoryId = categories[selectedCategoryIndex].id;
            isCategorySet = true;
          }
          // If not found, continue to check for last visited
        }
      }

      if (!isCategorySet) {
        if (pages.filter((page) => page.categoryId === undefined && page.isActive).length > 0) {
          selectedCategoryIndex = storageCategoryIndex > categories.length ? 0 : storageCategoryIndex;
          selectedCategoryId = selectedCategoryIndex === categories.length ? "0000" : categories[selectedCategoryIndex] ? categories[selectedCategoryIndex].id : undefined;
        }
        else {
          selectedCategoryIndex = storageCategoryIndex >= categories.length ? 0 : storageCategoryIndex;
          selectedCategoryId = selectedCategoryIndex === categories.length ? "0000" : categories[selectedCategoryIndex] ? categories[selectedCategoryIndex].id : undefined;
        }
      }

      firstRender = false;
    }

    // After categories layout changes, check if navigation should be shown
    setTimeout(() => {
      const categoriesList = document.querySelector("#categoriesList");
      if (categoriesList) {
        showCategoryNavigation = categoriesList.scrollWidth > categoriesList.clientWidth;
      }
    }, 0);
  });

  const onCategoryNavigationClick = (directionMultiplier) => {
    const categoriesList = document.querySelector("#categoriesList");
    const windowWidth = window.innerWidth;

    categoriesList.scrollLeft += directionMultiplier * (windowWidth * 0.55 - (windowWidth > 400 ? 100 : 20));
  };

  const onCategoryNext = () => {
    if (selectedCategoryIndex < categories.length - 1) {
      selectedCategoryIndex += 1;
      selectedCategoryId = categories[selectedCategoryIndex] ? categories[selectedCategoryIndex].id : undefined;
    }
    else if (showUncategorized && selectedCategoryIndex === categories.length - 1) {
      selectedCategoryIndex += 1;
      selectedCategoryId = "0000";
    }
  };

  const onCategoryPrevious = () => {
    if (selectedCategoryIndex > 0) {
      selectedCategoryIndex -= 1;
      selectedCategoryId = categories[selectedCategoryIndex] ? categories[selectedCategoryIndex].id : undefined;
    }
  };

  const onCategoryBarScroll = (event) => {
    if(
      Date.now() - lastCategoryNavigationTime < 400
      || (event.deltaMode === 0 && (event.deltaY >= -1 && event.deltaY <= 1))
    ) {
      return;
    }

    if (event.deltaY > 0) {
      onCategoryNext();
      lastCategoryNavigationTime = Date.now();
    }
    else {
      onCategoryPrevious();
      lastCategoryNavigationTime = Date.now();
    }
  };

  const onCategorySwipe = (event) => {
    if (
      !categories.length
      || Date.now() - lastCategoryNavigationTime < 300
      || (!isSlowSwipe && Date.now() - lastCategoryNavigationTime < 2000 && event.deltaX > -50 && event.deltaX < 50)
      || selectedCategoryIndex === 0 && event.deltaX < 0
      || (showUncategorized && selectedCategoryIndex === categories.length && event.deltaX > 0 || !showUncategorized && selectedCategoryIndex === categories.length - 1 && event.deltaX > 0)
    ) {
      return;
    }
    swipeNavigationBoxOffset -= event.deltaX / 2;

    if (swipeNavigationBoxOffset > 200) {
      isSlowSwipe = event.deltaX < 30 && event.deltaX > -30;
      swipeNavigationBoxOffset = 0;
      onCategoryPrevious();
      lastCategoryNavigationTime = Date.now();
    }
    else if (swipeNavigationBoxOffset < -200) {
      isSlowSwipe = event.deltaX < 30 && event.deltaX > -30;
      swipeNavigationBoxOffset = 0;
      onCategoryNext();
      lastCategoryNavigationTime = Date.now();
    }

    clearTimeout(swipeNavTimer);
    swipeNavTimer = setTimeout(() => {
      resetCategoryPosition(swipeNavigationBoxOffset);
    }, 200);    
  };

  const resetCategoryPosition = (currentPosition) => {
    const interval = setInterval(() => {
      if (currentPosition > 0) {
        currentPosition -= 5;
        if (currentPosition < 0) {
          currentPosition = 0;
        }
      }
      else if (currentPosition < 0) {
        currentPosition += 5;
        if (currentPosition > 0) {
          currentPosition = 0;
        }
      }
      else {
        clearInterval(interval);
      }
      swipeNavigationBoxOffset = currentPosition;
    }, 2);
  };

  // Change the selected category index when the categories change
  $:if(selectedCategoryId) {
    const categoryIndex = categories.findIndex((category) => category.id === selectedCategoryId);
    if (categoryIndex === -1) {
      selectedCategoryIndex = selectedCategoryIndex === categories.length ? categories.length : 0;
      selectedCategoryId = selectedCategoryIndex === categories.length ? "0000" : categories.length ? categories[0].id : undefined;
    }
    else {
      selectedCategoryIndex = categoryIndex;
      selectedCategoryId = categories[selectedCategoryIndex].id;
    }
  }

  $:showUncategorized = pages.filter((page) => page.categoryId === undefined && page.isActive).length > 0;

  // On mount and on resize check if the category navigation buttons should be shown
  $:if(windowInnerWidth) {
    const categoriesList = document.querySelector("#categoriesList");
    if (categoriesList) {
      showCategoryNavigation = categoriesList.scrollWidth > categoriesList.clientWidth;
    }
  }

  // Save the selected category index to local storage when it changes
  $: {
    saveCurrentSelectedCategoryIndex(selectedCategoryIndex);
  }
</script>

<svelte:window bind:innerWidth={windowInnerWidth} />

<div class="speedDial" on:wheel={categorySwipeNavigation ? onCategorySwipe : undefined}>
  {#each categories as category, index}
    <SpeedDialItems
      pages={pages.filter((page) => page.categoryId === category.id)}
      categories={categories}
      openQuickAdd={() => {isQuickAddOpen = true;}}
      isShown={selectedCategoryIndex === index}
      tileZoom={tileZoom}
      tileGrow={tileGrow}
      tileSafeZone={tileSafeZone}
      tileMinWidth={tileMinWidth}
      tileHeight={tileHeight}
      tileGap={tileGap}
      tileBorder={tileBorder}
      tileBorderRadius={tileBorderRadius}
      tileBorderColor={tileBorderColor}
      groupTileGap={groupTileGap}
      groupTileBorderRadius={groupTileBorderRadius}
      groupTileGrow={groupTileGrow}
      navbarCompact={navbarCompact}
      showPageQuickAdd={showPageQuickAdd}
      showElementsShadow={showElementsShadow}
      useFrostedGlass={useFrostedGlass}
      frostedGlassStrength={frostedGlassStrength}
      frostedGlassOpacity={frostedGlassOpacity}
      frostedGlassColor={frostedGlassColor}
      frostedGlassAccentColor={frostedGlassAccentColor}
      openPageInNewTab={openPageInNewTab}
      swipeNavigationOffset={swipeNavigationBoxOffset}
    />
  {/each}

  <SpeedDialItems
    pages={categories.length ? pages.filter((page) => page.categoryId === undefined) : pages}
    categories={categories}
    openQuickAdd={() => {isQuickAddOpen = true;}}
    isShown={selectedCategoryIndex === categories.length}
    tileZoom={tileZoom}
    tileGrow={tileGrow}
    tileSafeZone={tileSafeZone}
    tileMinWidth={tileMinWidth}
    tileHeight={tileHeight}
    tileGap={tileGap}
    tileBorder={tileBorder}
    tileBorderRadius={tileBorderRadius}
    tileBorderColor={tileBorderColor}
    groupTileGap={groupTileGap}
    groupTileBorderRadius={groupTileBorderRadius}
    groupTileGrow={groupTileGrow}
    navbarCompact={navbarCompact}
    showPageQuickAdd={showPageQuickAdd}
    showElementsShadow={showElementsShadow}
    useFrostedGlass={useFrostedGlass}
    frostedGlassStrength={frostedGlassStrength}
    frostedGlassOpacity={frostedGlassOpacity}
    frostedGlassColor={frostedGlassColor}
    frostedGlassAccentColor={frostedGlassAccentColor}
    openPageInNewTab={openPageInNewTab}
    swipeNavigationOffset={swipeNavigationBoxOffset}
  />

  {#if categorySwitchButtons && categories.length}
    <button
      class="categorySwitchButton previous"
      on:click={onCategoryPrevious}
    >
      <i class="fa-solid fa-chevron-left"/>
    </button>
    <button
      class="categorySwitchButton next"
      on:click={onCategoryNext}
    >
      <i class="fa-solid fa-chevron-right"/>
    </button>
  {/if}
</div>

{#if categories.length}
  <div class="categoriesContainer">
    <div
      class="categories"
      style={`
        ${
          useFrostedGlass
            ? `
              color: rgb(${frostedGlassAccentColor.r}, ${frostedGlassAccentColor.g}, ${frostedGlassAccentColor.b});
              border: none;
              backdrop-filter: blur(${frostedGlassStrength}px);
              -webkit-backdrop-filter: blur(${frostedGlassStrength}px);
              background-color: rgba(${frostedGlassColor.r}, ${frostedGlassColor.g}, ${frostedGlassColor.b}, ${frostedGlassOpacity}) !important;
            `
            : ''
        }
        ${showElementsShadow ? 'box-shadow: 0px 0px 10px rgba(20, 20, 20, 0.2);' : ''}
      `}
      on:wheel={categoryBarScroll ? onCategoryBarScroll : undefined}
    >
      {#if showCategoryNavigation}
        <div class="categoryNavigation">
          <i class="fa-solid fa-chevron-left" on:click={() => onCategoryNavigationClick(-1)} />
        </div>
      {/if}

      <div id="categoriesList" class="categoriesList">
        {#each categories as category, index}
          <div
            class="category"
            class:selected={selectedCategoryIndex === index}
            on:click={() => {
              selectedCategoryIndex = index;
              selectedCategoryId = category.id;
            }}
          >
            {category.name}
          </div>
        {/each}

        {#if showUncategorized}
          <div
            class="category"
            class:selected={selectedCategoryIndex === categories.length}
            on:click={() => {
              selectedCategoryIndex = categories.length;
              selectedCategoryId = "0000";
            }}
          >
            Uncategorized
          </div>
        {/if}
      </div>

      {#if showCategoryNavigation}
        <div class="categoryNavigation">
          <i class="fa-solid fa-chevron-right" on:click={() => onCategoryNavigationClick(1)} />
        </div>
      {/if}
    </div>
  </div>
{/if}

{#if isQuickAddOpen}
  <PageQuickAddModal
    pages={pages}  
    categories={categories}
    selectedCategoryIndex={selectedCategoryIndex}
    bind:modalActive={isQuickAddOpen}
  />
{/if}

<style>
  .speedDial {
    position: relative;
    height: 100%;
  }
  .categoriesContainer {
    display: flex;
    justify-content: center;
    height: 32px;
    position: absolute;
    bottom: 8px;
    left: 0;
    right: 0;
  }
  .categoriesContainer:not(:has(.categoryNavigation)) .categories {
    padding: 0px 16px;
  }
  .categories {
    display: flex;
    align-items: center;
    padding: 0px 4px;
    border-radius: 100px;
    border: 2px solid;
    border-color: rgba(0, 0, 0, 0.4);
    background-color: rgba(0, 0, 0, 0.35);
    color: white;
    transition: 0.3s;
    z-index: 5;
  }
  .categoryNavigation i {
    padding: 4px 8px;
    cursor: pointer;
    transition: 0.3s;
    font-size: 0.9em;
    user-select: none;
  }
  .categoryNavigation i:hover {
    opacity: 0.8;
  }
  .categoriesList {
    display: flex;
    gap: 16px;
    max-width: 55vw;
    overflow-x: auto;
    -ms-overflow-style: none;
    scrollbar-width: none;
    scroll-behavior: smooth;
  }
  .category {
    line-height: 1.8rem;
    cursor: pointer;
    transition: 0.3s;
    flex-shrink: 0;
    font-size: 1.1em;
  }
  .category:hover {
    opacity: 0.8;
  }
  .category.selected {
    color: #3a99ff;
    text-shadow: 0px 0px 2px #3a99ff;
  }
  .category.selected:hover {
    color: #2880de;
    opacity: 1;
  }
  .categorySwitchButton {
    position: fixed;
    z-index: 5;
    top: 50vh;
    border: none;
    outline: none;
    padding: 0;
    background-color: transparent;
    color: white;
    text-shadow: 0px 0px 4px rgba(0, 0, 0, 0.4);
    font-size: 40px;
    cursor: pointer;
    transition: 0.3s;
  }
  .categorySwitchButton:hover {
    transform: scale(1.2);
  }
  .categorySwitchButton.next {
    right: 12px;
  }
  .categorySwitchButton.previous {
    left: 12px;
  }
</style>
